697   // real entry into the function we seed the PHI with the identity constant for
698   // the accumulation operation.  For any other existing branches to this block
699   // (due to other tail recursions eliminated) the accumulator is not modified.
700   // Because we haven't added the branch in the current block to HeaderBB yet,
701   // it will not show up as a predecessor.
702   for (pred_iterator PI = PB; PI != PE; ++PI) {
703     BasicBlock *P = *PI;
