709         // We didn't pass `AllowRHSConstant = true` in getIdentity above because
710         // the identity for shifts is zero, which is not valid for the LHS.
711         // We need the value of the base case(s) of the function to
712         // initialize the accumulator.
713         InitialValue = BaseCaseValue;
714       }
715       AccPN->addIncoming(InitialValue, P);
