428     // Case 3: select with a constant arm.
429     if (auto *SI = dyn_cast<SelectInst>(RV)) {
430       if (auto *CTrue = dyn_cast<Constant>(SI->getTrueValue()))
431         return CTrue;
432       if (auto *CFalse = dyn_cast<Constant>(SI->getFalseValue()))
433         return CFalse;
434       return nullptr;
435     }
436 
437     return nullptr;
438   };
439 
440   for (BasicBlock &BB : F) {
441     if (auto *RI = dyn_cast<ReturnInst>(BB.getTerminator())) {
442       Value *RV = RI->getReturnValue();
443       Constant *Candidate = TryGetConstantBaseCase(RV);
444       if (!Candidate)
445         return nullptr;
446 
447       if (!BaseCaseVal)
448         BaseCaseVal = Candidate;
449       else if (BaseCaseVal != Candidate)
450         return nullptr;
451     }
452   }
453 
454   return BaseCaseVal;
455 }
