457 // This function checks whether the instruction I can be used
458 // to perform accumulator recursion elimination for the
459 // call instruction CI.
460 // In the presence of pseudo-associative operations, it returns
461 // the base case constant value to both indicate success and
462 // provide the value needed to initialize the accumulator.
463 static std::variant<bool, Constant *>
464 canTransformAccumulatorRecursion(Instruction *I, CallInst *CI) {
465   auto IsPseudoAssociative = isPseudoAssociative(I);
466   if ((!I->isAssociative() || !I->isCommutative()) && !IsPseudoAssociative)
467     return false;
468 
469   assert(I->getNumOperands() >= 2 &&
470          "Associative/commutative operations should have at least 2 args!");
471 
472   Constant *BaseCaseConst = nullptr;
473   if (IsPseudoAssociative) {
474     // For pseudo-associative operations, we require that the recursive call
475     // is always on the first operand.
476     if (I->getOperand(0) != CI)
477       return false;
478 
479     BaseCaseConst = getReturnValue(*CI->getCalledFunction());
480     if (!BaseCaseConst)
481       return false;
482   } else {
483     if (IntrinsicInst *II = dyn_cast<IntrinsicInst>(I)) {
484       // Accumulators must have an identity.
485       if (!ConstantExpr::getIntrinsicIdentity(II->getIntrinsicID(),
486                                               I->getType()))
487         return false;
488     }
489 
490     // Exactly one operand should be the result of the call instruction.
491     if ((I->getOperand(0) == CI && I->getOperand(1) == CI) ||
492         (I->getOperand(0) != CI && I->getOperand(1) != CI))
493       return false;
494   }
495 
496   // The only user of this instruction we allow is a single return instruction.
497   if (!I->hasOneUse() || !isa<ReturnInst>(I->user_back()))
498     return false;
499 
500   if (BaseCaseConst)
501     return BaseCaseConst;
502 
503   return true;
504 }
