586 CallInst *TailRecursionEliminator::findTRECandidate(BasicBlock *BB) {
587   Instruction *TI = BB->getTerminator();
588 
589   if (&BB->front() == TI) // Make sure there is something before the terminator.
590     return nullptr;
591 
592   // Scan backwards from the return, checking to see if there is a tail call in
593   // this block.  If so, set CI to it.
594   CallInst *CI = nullptr;
595   BasicBlock::iterator BBI(TI);
596   while (true) {
597     CI = dyn_cast<CallInst>(BBI);
598     if (CI && CI->getCalledFunction() == &F)
599       break;
600 
601     if (BBI == BB->begin())
602       return nullptr;          // Didn't find a potential tail call.
603     --BBI;
604   }
605 
606   assert((!CI->isTailCall() || !CI->isNoTailCall()) &&
607          "Incompatible call site attributes(Tail,NoTail)");
608   if (!CI->isTailCall())
609     return nullptr;
610 
611   // As a special case, detect code like this:
612   //   double fabs(double f) { return __builtin_fabs(f); } // a 'fabs' call
613   // and disable this xform in this case, because the code generator will
614   // lower the call to fabs into inline code.
615   if (BB == &F.getEntryBlock() && &BB->front() == CI &&
616       &*std::next(BB->begin()) == TI && CI->getCalledFunction() &&
617       !TTI->isLoweredToCall(CI->getCalledFunction())) {
618     // A single-block function with just a call and a return. Check that
619     // the arguments match.
620     auto I = CI->arg_begin(), E = CI->arg_end();
621     Function::arg_iterator FI = F.arg_begin(), FE = F.arg_end();
622     for (; I != E && FI != FE; ++I, ++FI)
623       if (*I != &*FI) break;
624     if (I == E && FI == FE)
625       return nullptr;
626   }
627 
628   return CI;
629 }
